function totalFormatsCount(){
  return (FORMATS_DATA.lexis.length + FORMATS_DATA.grammar.length + FORMATS_DATA.reading.length);
}

function init(){
  document.getElementById('statsFormats').textContent = totalFormatsCount();
  document.getElementById('statsTotal').textContent = totalFormatsCount() * 3;

  // Category buttons
  document.querySelectorAll('#categoryRow .choice-btn').forEach(btn=>{
    btn.addEventListener('click', ()=>{
      state.category = btn.dataset.category;
      document.querySelectorAll('#categoryRow .choice-btn').forEach(b=>b.classList.toggle('active', b===btn));
      state.formatId = null;
      renderFormats();
      updatePrompt();
    });
  });

  // Age buttons
  document.querySelectorAll('#ageRow .choice-btn').forEach(btn=>{
    btn.addEventListener('click', ()=>{
      state.age = btn.dataset.age;
      document.querySelectorAll('#ageRow .choice-btn').forEach(b=>b.classList.toggle('active', b===btn));
      const lens = FORMATS_DATA.ageLenses[state.age];
      document.getElementById('ageHint').textContent = lens ? `Тон: ${lens.tone}` : '';
      // Если текущий формат больше не подходит новому возрасту — сбрасываем выбор
      if(state.formatId){
        const fmt = getCurrentFormat();
        if(!fmt || !fmt.ages.includes(state.age)){
          state.formatId = null;
          renderSelectedBanner();
        }
      }
      renderFormats();
      updatePrompt();
    });
  });

  document.getElementById('formatSearch').addEventListener('input', renderFormats);
  document.getElementById('randomFormatBtn').addEventListener('click', pickRandomFormat);

  // Styles
  renderStyles();
  document.getElementById('styleSearch').addEventListener('input', ()=>renderStyles(true));

  // language customs
  setupCustomSelect('targetLanguage', 'targetLanguageCustom');
  setupCustomSelect('nativeLanguage', 'nativeLanguageCustom');

  // All fields trigger prompt update
  const liveIds = ['targetLanguage','targetLanguageCustom','nativeLanguage','nativeLanguageCustom',
    'level','workMode','volume','outputMode','topicInput','styleCustom','extraNotes',
    'optAnswerKey','optHeader','optMethodNote','optBilingual','optDifferentiation'];
  liveIds.forEach(id=>{
    const el = document.getElementById(id);
    el.addEventListener('input', updatePrompt);
    el.addEventListener('change', updatePrompt);
  });
  document.getElementById('styleCustom').addEventListener('input', ()=>{
    if(document.getElementById('styleCustom').value.trim()){
      document.querySelectorAll('input[name=style]').forEach(r=>r.checked=false);
      state.styleId = null;
    }
  });

  document.getElementById('copyBtn').addEventListener('click', copyPrompt);
  document.getElementById('downloadBtn').addEventListener('click', downloadPrompt);
  document.getElementById('clearHistoryBtn').addEventListener('click', clearHistory);

  renderFormats();
  renderHistory();
  updatePrompt();
}

function setupCustomSelect(selectId, customId){
  const sel = document.getElementById(selectId);
  const custom = document.getElementById(customId);
  sel.addEventListener('change', ()=>{
    custom.style.display = sel.value === '__custom__' ? 'block' : 'none';
    updatePrompt();
  });
}

function getFormatsForCurrentCategory(){
  if(!state.category) return [];
  return FORMATS_DATA[state.category] || [];
}

// Форматы, подходящие текущей категории И текущей возрастной группе
function getAvailableFormats(){
  if(!state.category || !state.age) return [];
  return getFormatsForCurrentCategory().filter(f=>f.ages.includes(state.age));
}

function renderFormats(){
  const grid = document.getElementById('formatGrid');
  const emptyMsg = document.getElementById('formatEmptyMsg');
  grid.innerHTML = '';

  if(!state.category || !state.age){
    emptyMsg.style.display = 'block';
    emptyMsg.textContent = 'Сначала выберите категорию и возраст выше 👆';
    grid.style.display = 'none';
    return;
  }
  emptyMsg.style.display = 'none';
  grid.style.display = 'grid';

  const query = document.getElementById('formatSearch').value.trim().toLowerCase();
  const list = getAvailableFormats().filter(f=>{
    if(!query) return true;
    return f.name.toLowerCase().includes(query) || f.goal.toLowerCase().includes(query);
  });

  if(list.length === 0){
    grid.style.display='none';
    emptyMsg.style.display='block';
    emptyMsg.textContent = 'Ничего не найдено по запросу «' + query + '»';
    return;
  }

  list.forEach(fmt=>{
    const card = document.createElement('div');
    card.className = 'format-card' + (state.formatId===fmt.id ? ' active' : '');
    card.innerHTML = `<div class="fc-name">${fmt.name}</div><div class="fc-goal">${fmt.goal}</div>`;
    card.addEventListener('click', ()=>selectFormat(fmt.id));
    grid.appendChild(card);
  });
}

function renderStyles(preserveScroll){
  const grid = document.getElementById('styleGrid');
  const query = document.getElementById('styleSearch').value.trim().toLowerCase();
  const list = STYLES.filter(s=>{
    if(!query) return true;
    return s.title.toLowerCase().includes(query) || s.value.toLowerCase().includes(query);
  });

  grid.innerHTML = '';
  if(list.length === 0){
    grid.innerHTML = '<div class="format-empty" style="grid-column:1/-1">Ничего не найдено. Попробуйте другой запрос или впишите свой стиль ниже 👇</div>';
    return;
  }

  list.forEach(s=>{
    const label = document.createElement('label');
    label.className = 'style-opt';
    label.innerHTML = `<input type="radio" name="style" value="${escapeHtml(s.value)}" ${state.styleId===s.id?'checked':''}><span>${s.emoji} ${s.title}</span>`;
    const input = label.querySelector('input');
    input.addEventListener('change', ()=>{
      state.styleId = s.id;
      document.getElementById('styleCustom').value = '';
      updatePrompt();
    });
    grid.appendChild(label);
  });
}

function escapeHtml(str){
  return str.replace(/&/g,'&amp;').replace(/"/g,'&quot;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

function pickRandomFormat(){
  if(!state.category){
    alert('Сначала выберите категорию (Лексика / Грамматика / Чтение).');
    return;
  }
  if(!state.age){
    alert('Сначала выберите возрастную группу.');
    return;
  }
  const list = getAvailableFormats();
  if(list.length === 0){
    alert('Для этой возрастной группы нет доступных форматов в данной категории.');
    return;
  }
  const random = list[Math.floor(Math.random()*list.length)];
  document.getElementById('formatSearch').value = '';
  selectFormat(random.id);
}

function selectFormat(id){
  state.formatId = id;
  renderFormats();
  renderSelectedBanner();
  document.getElementById('paramsStep').scrollIntoView({behavior:'smooth', block:'nearest'});
  updatePrompt();
}

function getCurrentFormat(){
  if(!state.category || !state.formatId) return null;
  return getFormatsForCurrentCategory().find(f=>f.id === state.formatId) || null;
}

function renderSelectedBanner(){
  const banner = document.getElementById('selectedFormatBanner');
  const fmt = getCurrentFormat();
  if(!fmt){ banner.style.display='none'; return; }
  banner.style.display='block';
  banner.innerHTML = `Выбран формат: <b>${fmt.name}</b> (${CATEGORY_LABELS[state.category]}, ${FORMATS_DATA.ageLenses[state.age].label}) — <i>${fmt.goal}</i>`;
}

function resolveSelectValue(selectId, customId){
  const sel = document.getElementById(selectId);
  if(sel.value === '__custom__'){
    return document.getElementById(customId).value.trim();
  }
  return sel.value;
}

function buildPrompt(){
  const fmt = getCurrentFormat();
  if(!state.category || !state.age || !fmt) return '';

  const lens = FORMATS_DATA.ageLenses[state.age];
  const targetLang = resolveSelectValue('targetLanguage','targetLanguageCustom') || 'английский';
  const nativeLang = resolveSelectValue('nativeLanguage','nativeLanguageCustom');
  const level = document.getElementById('level').value;
  const workMode = document.getElementById('workMode').value;
  const volume = document.getElementById('volume').value;
  const outputMode = document.getElementById('outputMode').value;
  const topic = document.getElementById('topicInput').value.trim();
  const extra = document.getElementById('extraNotes').value.trim();

  let style = document.getElementById('styleCustom').value.trim();
  if(!style){
    const checkedStyle = document.querySelector('input[name=style]:checked');
    style = checkedStyle ? checkedStyle.value : '';
  }

  const optAnswerKey = document.getElementById('optAnswerKey').checked;
  const optHeader = document.getElementById('optHeader').checked;
  const optMethodNote = document.getElementById('optMethodNote').checked;
  const optBilingual = document.getElementById('optBilingual').checked;
  const optDifferentiation = document.getElementById('optDifferentiation').checked;

  const lines = [];

  // ---- ROLE ----
  lines.push(`Ты — опытный методист и автор учебных материалов по ${targetLang}у языку с многолетним стажем преподавания возрастной группе «${lens.label}». Ты прекрасно понимаешь возрастную психологию, мотивацию и типичные трудности этой аудитории, а также умеешь оформлять материалы визуально привлекательно и методически грамотно.`);
  lines.push('');

  // ---- TASK ----
  lines.push(`ЗАДАЧА: Создай готовый к использованию на занятии рабочий лист (worksheet) в формате «${fmt.name}» по направлению «${CATEGORY_LABELS[state.category]}».`);
  lines.push('');
  lines.push(`ЦЕЛЬ ФОРМАТА: ${fmt.goal}.`);
  lines.push('');
  lines.push(`ЧТО СОЗДАТЬ: ${fmt.instruction}`);
  lines.push('');

  // ---- TOPIC ----
  if(topic){
    lines.push(`ТЕМА / ЛЕКСИКА / ГРАММАТИЧЕСКАЯ СТРУКТУРА: ${topic}.`);
  } else {
    lines.push(`ТЕМА / ЛЕКСИКА / ГРАММАТИЧЕСКАЯ СТРУКТУРА: [впиши сюда конкретную тему, список слов, грамматическую конструкцию или текст, на основе которых нужно построить рабочий лист].`);
  }
  lines.push('');

  // ---- AUDIENCE ----
  const audienceParts = [];
  audienceParts.push(`Возраст учеников: ${lens.label}.`);
  if(level) audienceParts.push(`Уровень владения языком: ${level}.`);
  audienceParts.push(`Формат занятия: ${workMode}.`);
  lines.push('ЦЕЛЕВАЯ АУДИТОРИЯ:');
  lines.push(audienceParts.map(x=>'— '+x).join('\n'));
  lines.push('');

  // ---- AGE ADAPTATION ----
  lines.push('АДАПТАЦИЯ ПОД ВОЗРАСТ (обязательно учитывай при составлении контента):');
  lines.push(`— Тон и стиль общения: ${lens.tone}.`);
  lines.push(`— Уровень сложности и подача: ${lens.complexity}.`);
  lines.push(`— Объём и структура: ${lens.length}.`);
  lines.push('');

  // ---- LANGUAGE ----
  lines.push(`ЯЗЫК МАТЕРИАЛА: весь учебный контент (задания, тексты, лексика) — на ${targetLang}м языке.`);
  if(nativeLang){
    if(optBilingual){
      lines.push(`Инструкции к заданиям дай на двух языках: сначала на ${targetLang}м, затем краткий перевод на ${nativeLang}м языке (в скобках или курсивом).`);
    } else {
      lines.push(`Инструкции к заданиям (Instructions) можно продублировать на ${nativeLang}м языке для удобства понимания учениками.`);
    }
  }
  lines.push('');

  // ---- VISUAL STYLE ----
  lines.push('ВИЗУАЛЬНОЕ ОФОРМЛЕНИЕ:');
  lines.push(`— Общий стиль: ${style || lens.visual}.`);
  if(style) lines.push(`— Дополнительно учти возрастную эстетику: ${lens.visual}.`);
  lines.push(`— Объём материала: ${volume}.`);
  lines.push('— Предусмотри чёткую нумерацию заданий, достаточно свободного места для письменных ответов учеников, аккуратную сетку/рамки там, где это уместно для формата.');
  lines.push('');

  // ---- OPTIONS ----
  const optionLines = [];
  if(optHeader) optionLines.push('В самом верху листа размести шапку с полями: Имя ученика / Дата / Оценка (или Балл).');
  if(optAnswerKey) optionLines.push('В конце документа (на отдельном блоке или странице «Answer Key / Ключ с ответами») приведи полные правильные ответы на все задания.');
  if(optDifferentiation) optionLines.push('Добавь после основного задания два дополнительных мини-блока: «Задание полегче» (для учеников послабее) и «Задание посложнее» (для более сильных учеников), сохранив ту же тему.');
  if(optMethodNote) optionLines.push('В самом конце добавь отдельный блок «Заметка для преподавателя»: цель урока, ожидаемый результат, критерии успешного выполнения и рекомендацию, как использовать материал на занятии (сколько времени закладывать, как проверить).');
  if(optionLines.length){
    lines.push('ДОПОЛНИТЕЛЬНЫЕ ЭЛЕМЕНТЫ:');
    optionLines.forEach(o=>lines.push('— '+o));
    lines.push('');
  }

  // ---- OUTPUT FORMAT ----
  if(outputMode === 'image'){
    lines.push('ФОРМАТ РЕЗУЛЬТАТА: это промпт для генератора изображений. Опиши результат так, чтобы он выглядел как ЦЕЛЬНОЕ, готовое к печати изображение одностраничного (или разворотного) рабочего листа формата A4: со всеми текстами, иллюстрациями, рамками и разметкой, скомпонованными в единую композицию, похожую на профессионально свёрстанный учебный worksheet. Убедись, что весь текст на изображении корректен и читаем, а макет — чистый, ровный, без перекрытий элементов.');
  } else {
    lines.push('ФОРМАТ РЕЗУЛЬТАТА: выведи готовый, полностью прописанный текст рабочего листа (все задания, тексты, инструкции, банки слов и т.д.) в чистом, аккуратно структурированном виде (с заголовками, нумерацией, таблицами при необходимости), готовый для переноса в документ или дизайн-редактор для дальнейшей вёрстки.');
  }
  lines.push('');

  // ---- EXTRA ----
  if(extra){
    lines.push('ДОПОЛНИТЕЛЬНЫЕ ПОЖЕЛАНИЯ ПРЕПОДАВАТЕЛЯ:');
    lines.push(extra);
    lines.push('');
  }

  lines.push('Прежде чем выводить финальный результат, убедись, что: (1) содержание полностью соответствует заявленной теме и структуре формата, (2) язык и сложность строго соответствуют возрасту и уровню, (3) все инструкции к заданиям однозначны и понятны ученику без участия учителя.');

  return lines.join('\n');
}

function updatePrompt(){
  const promptText = buildPrompt();
  const output = document.getElementById('promptOutput');
  output.value = promptText || 'Заполните шаги 1–3 слева (категория → возраст → формат), чтобы здесь появился готовый промпт.';
  document.getElementById('copyMsg').textContent = '';
}

function copyPrompt(){
  const output = document.getElementById('promptOutput');
  if(!output.value || !state.formatId){ return; }
  output.select();
  try{
    document.execCommand('copy');
  }catch(e){}
  if(navigator.clipboard && navigator.clipboard.writeText){
    navigator.clipboard.writeText(output.value).catch(()=>{});
  }
  document.getElementById('copyMsg').textContent = '✓ Промпт скопирован в буфер обмена';
  saveToHistory();
  setTimeout(()=>{ document.getElementById('copyMsg').textContent=''; }, 3000);
}

function downloadPrompt(){
  const output = document.getElementById('promptOutput');
  if(!output.value || !state.formatId) return;
  const fmt = getCurrentFormat();
  const filename = `prompt_${state.category}_${state.age}_${(fmt?fmt.id:'x')}.txt`;
  const blob = new Blob([output.value], {type:'text/plain;charset=utf-8'});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = filename;
  document.body.appendChild(a); a.click(); document.body.removeChild(a);
  URL.revokeObjectURL(url);
  saveToHistory();
}

// ---------------- HISTORY (localStorage) ----------------
const HISTORY_KEY = 'pc_prompt_history_v1';

function loadHistory(){
  try{
    const raw = localStorage.getItem(HISTORY_KEY);
    return raw ? JSON.parse(raw) : [];
  }catch(e){ return []; }
}

function saveToHistory(){
  const fmt = getCurrentFormat();
  if(!fmt) return;
  const history = loadHistory();
  const entry = {
    id: Date.now(),
    title: fmt.name,
    meta: `${CATEGORY_LABELS[state.category]} · ${FORMATS_DATA.ageLenses[state.age].label}${document.getElementById('topicInput').value.trim() ? ' · ' + document.getElementById('topicInput').value.trim() : ''}`,
    text: document.getElementById('promptOutput').value,
  };
  history.unshift(entry);
  while(history.length > 20) history.pop();
  try{ localStorage.setItem(HISTORY_KEY, JSON.stringify(history)); }catch(e){}
  renderHistory();
}

function renderHistory(){
  const list = document.getElementById('historyList');
  const history = loadHistory();
  list.innerHTML = '';
  if(history.length === 0){
    list.innerHTML = '<div class="history-empty">История пуста — скопируйте или скачайте промпт, чтобы он появился здесь.</div>';
    return;
  }
  history.forEach(item=>{
    const div = document.createElement('div');
    div.className = 'history-item';
    div.innerHTML = `<div class="hi-title">${item.title}</div><div class="hi-meta">${item.meta}</div>`;
    div.addEventListener('click', ()=>{
      document.getElementById('promptOutput').value = item.text;
    });
    list.appendChild(div);
  });
}

function clearHistory(){
  try{ localStorage.removeItem(HISTORY_KEY); }catch(e){}
  renderHistory();
}

